                {PHASE_LABELS[p]}
              </span>
              {isActive && phase !== "complete" && (
                <span style={{ marginLeft: 4, animation: "pulse 1.5s infinite" }}>
                  ...
                </span>
              )}
            </div>
          );
        })}
      </div>

      {/* Error state */}
      {phase === "error" && (
        <div style={{ background: "#fef2f2", color: "#b91c1c", padding: "12px 16px", borderRadius: 8, fontSize: 14 }}>
          {error}
        </div>
