    10→
    11→type Step = "signin" | "profile" | "scrape" | "poke" | "queue";
    12→
    13→export default function PhonePage() {
    14→  const [step, setStep] = useState<Step>("signin");
    15→  const [user, setUser] = useState<UserProfile | null>(null);
    16→  const [error, setError] = useState("");
    17→
    18→  function handleSignIn(profile: UserProfile) {
    19→    setUser(profile);
    20→    setError("");
    21→    // If they already have a phone number, skip profile step
    22→    if (profile.phone) {
    23→      setStep("scrape");
    24→    } else {
    25→      setStep("profile");
    26→    }
    27→  }
    28→
    29→  function handleProfileComplete(updated: UserProfile) {
    30→    setUser(updated);
    31→    setError("");
    32→    setStep("scrape");
    33→  }
    34→
    35→  function handlePokeSkip() {
    36→    setStep("queue");
    37→  }
    38→
    39→  async function handleReset() {
    40→    if (!user) return;
    41→    try {
    42→      await clearUserData(user.id);
    43→      setUser(null);
    44→      setStep("signin");
    45→      setError("");
    46→    } catch (err) {
    47→      setError(err instanceof Error ? err.message : "Failed to reset");
    48→    }
    49→  }
    50→
    51→  return (
    52→    <main
    53→      style={{
    54→        minHeight: "100dvh",
    55→        display: "flex",
    56→        flexDirection: "column",
    57→        justifyContent: "center",
    58→        padding: "24px 20px",
    59→        maxWidth: 400,
    60→        margin: "0 auto",
    61→        fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
    62→      }}
    63→    >
    64→      {error && (
    65→        <div
    66→          style={{
    67→            background: "#fef2f2",
    68→            color: "#b91c1c",
