    70→            borderRadius: 8,
    71→            marginBottom: 20,
    72→            fontSize: 14,
    73→          }}
    74→        >
    75→          {error}
    76→        </div>
    77→      )}
    78→
    79→      {step === "signin" && (
    80→        <GoogleSignIn onSuccess={handleSignIn} onError={setError} />
    81→      )}
    82→
    83→      {step === "profile" && user && (
    84→        <ProfileForm
    85→          user={user}
    86→          onComplete={handleProfileComplete}
    87→          onError={setError}
    88→        />
    89→      )}
    90→
    91→      {step === "scrape" && user && (
