    95→      {step === "poke" && <PokeLink onContinue={handlePokeSkip} />}
    96→
    97→      {step === "queue" && user && <QueueStatus userId={user.id} />}
    98→
    99→      {user && (
   100→        <button
   101→          onClick={handleReset}
   102→          style={{
   103→            marginTop: 24,
   104→            padding: "8px 16px",
   105→            fontSize: 13,
