"use client";

import { useState } from "react";
import { UserProfile, clearUserData } from "@/lib/api";
import GoogleSignIn from "@/components/phone/GoogleSignIn";
import ProfileForm from "@/components/phone/ProfileForm";
import ScrapeResults from "@/components/phone/ScrapeResults";
import PokeLink from "@/components/phone/PokeLink";
import QueueStatus from "@/components/phone/QueueStatus";

type Step = "signin" | "profile" | "scrape" | "poke" | "queue";

export default function PhonePage() {
  const [step, setStep] = useState<Step>("signin");
  const [user, setUser] = useState<UserProfile | null>(null);
  const [error, setError] = useState("");

  function handleSignIn(profile: UserProfile) {
    setUser(profile);
    setError("");
    // If they already have a phone number, skip profile step
    if (profile.phone) {
      setStep("scrape");
    } else {
      setStep("profile");
    }
  }

  function handleProfileComplete(updated: UserProfile) {
    setUser(updated);
    setError("");
    setStep("scrape");
  }

  function handlePokeSkip() {
    setStep("queue");
  }

  async function handleReset() {
    if (!user) return;
    try {
      await clearUserData(user.id);
      setUser(null);
      setStep("signin");
      setError("");
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to reset");
    }
  }

  return (
    <main
      style={{
        minHeight: "100dvh",
        display: "flex",
        flexDirection: "column",
        justifyContent: "center",
        padding: "24px 20px",
        maxWidth: 400,
        margin: "0 auto",
        fontFamily: "-apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif",
      }}
    >
      {error && (
        <div
          style={{
            background: "#fef2f2",
            color: "#b91c1c",
            padding: "12px 16px",
            borderRadius: 8,
            marginBottom: 20,
            fontSize: 14,
          }}
        >
          {error}
        </div>
      )}

      {step === "signin" && (
        <GoogleSignIn onSuccess={handleSignIn} onError={setError} />
      )}

      {step === "profile" && user && (
        <ProfileForm
          user={user}
          onComplete={handleProfileComplete}
          onError={setError}
        />
      )}

      {step === "scrape" && user && (
        <ScrapeResults userId={user.id} onContinue={() => setStep("poke")} />
      )}

      {step === "poke" && <PokeLink onContinue={handlePokeSkip} />}

      {step === "queue" && user && <QueueStatus userId={user.id} />}

      {user && (
        <button
          onClick={handleReset}
          style={{
            marginTop: 24,
            padding: "8px 16px",
            fontSize: 13,
            color: "#999",
            background: "transparent",
            border: "1px solid #e5e7eb",
            borderRadius: 6,
            cursor: "pointer",
            alignSelf: "center",
          }}
        >
          Reset (clear data &amp; restart)
        </button>
      )}
    </main>
  );
}

