     1→import type { DetectedGesture, SwipeState } from "@/types/gestures";
     2→
     3→const SWIPE_THRESHOLD = 0.15; // Minimum x-displacement (normalized 0-1)
     4→const SWIPE_WINDOW_MS = 500; // Time window to detect swipe
     5→const GESTURE_COOLDOWN_MS = 800; // Minimum time between gestures
     6→const MIN_CONFIDENCE = 0.6; // Minimum confidence for built-in gestures
     7→
     8→export function createSwipeState(): SwipeState {
     9→  return { positions: [], lastGestureTime: 0 };
    10→}
    11→
    12→export function detectSwipe(
    13→  state: SwipeState,
    14→  currentX: number,
    15→  currentTimestamp: number
    16→): DetectedGesture | null {
    17→  // Add current position
    18→  state.positions.push({ x: currentX, timestamp: currentTimestamp });
    19→
    20→  // Remove positions outside the time window
    21→  const cutoff = currentTimestamp - SWIPE_WINDOW_MS;
    22→  state.positions = state.positions.filter((p) => p.timestamp >= cutoff);
    23→
    24→  // Need at least 5 data points for reliable swipe detection
    25→  if (state.positions.length < 5) return null;
    26→
    27→  // Enforce cooldown (skip if no gesture has been detected yet)
    28→  if (
    29→    state.lastGestureTime > 0 &&
    30→    currentTimestamp - state.lastGestureTime < GESTURE_COOLDOWN_MS
    31→  )
    32→    return null;
    33→
    34→  const oldest = state.positions[0];
    35→  const dx = currentX - oldest.x;
    36→
    37→  if (Math.abs(dx) < SWIPE_THRESHOLD) return null;
    38→
    39→  const type = dx > 0 ? "swipe_right" : "swipe_left";
    40→
    41→  // Reset state after detection
    42→  state.positions = [];
    43→  state.lastGestureTime = currentTimestamp;
    44→
    45→  return {
    46→    type,
    47→    confidence: Math.min(Math.abs(dx) / 0.3, 1), // Scale confidence by displacement
    48→    timestamp: currentTimestamp,
    49→  };
    50→}
    51→
    52→export function classifyBuiltInGesture(
    53→  gestureName: string,
    54→  score: number,
    55→  timestamp: number
    56→): DetectedGesture | null {
    57→  if (score < MIN_CONFIDENCE) return null;
    58→
    59→  switch (gestureName) {
    60→    case "Thumb_Up":
    61→      return { type: "thumbs_up", confidence: score, timestamp };
    62→    case "Thumb_Down":
    63→      return { type: "thumbs_down", confidence: score, timestamp };
    64→    default:
    65→      return null;
    66→  }
    67→}
    68→

